const express = require('express');
const app = express();
const bodyParser = require('body-parser');
const uuid = require('uuid');

const clients = [
  { client_id: 'client1', redirect_uri: 'https://client1.com/callback' },
  { client_id: 'client2', redirect_uri: 'https://client2.com/callback' }
];

const authorizationCodes = {};

app.use(bodyParser.urlencoded({ extended: true }));

app.get('/authorize', (req, res) => {
  const { client_id, redirect_uri, state } = req.query;

  const client = clients.find(c => c.client_id === client_id && c.redirect_uri === redirect_uri);

  if (!client) {
    return res.status(400).send('Invalid client_id or redirect_uri');
  }

  const code = uuid.v4();
  authorizationCodes[code] = { client_id, state };

  res.redirect(`${redirect_uri}?code=${code}&state=${state}`);
});

app.post('/token', (req, res) => {
  const { client_id, code, redirect_uri } = req.body;

  if (!client_id || !code || !redirect_uri) {
    return res.status(400).send('Invalid request');
  }

  const client = clients.find(c => c.client_id === client_id && c.redirect_uri === redirect_uri);

  if (!client) {
    return res.status(400).send('Invalid client credentials');
  }

  const authCode = authorizationCodes[code];

  if (!authCode || authCode.client_id !== client_id) {
    return res.status(400).send('Invalid authorization code');
  }

  // Generate access token and handle token response
  const accessToken = uuid.v4();
  res.json({ access_token: accessToken });
});

